import logo from './logo.svg';
import {useState} from "react";

import './App.css';


function App() {
  const [isVisible, setIsVisible] = useState(true);


  return (
    <div className="App">
      <header className="App-header">
        <h1>簡易メモアプリケーション</h1>
        <p>
          このアプリでは、タイトル・内容・タグを入力して
          メモを作成できます。
        </p>

        <button
          onClick={() =>
            console.log("このアプリはメモ管理用のReactアプリです")
          }
        >
          このアプリについて
        </button>

      {/* ボタンを押すと setIsVisible が実行され、isVisible の値が反転(true/false)する */}
      <button onClick={() => setIsVisible(!isVisible)}>
      フォーム表示切り替え
      </button>

     {isVisible && (
     <div
      style={{
      padding: 20,
      border: "1px solid #61dafb",
      marginTop: 20,
      }}
     >
    <p>ここにメモ入力フォームが表示されます</p>
  </div>
)}
        <a
          className="App-link"
          href="https://reactjs.org"
          target="_blank"
          rel="noopener noreferrer"
        >
          Learn React
        </a>
      </header>
    </div>
  );
}

export default App;
